local _M = {}

-- Rate limiter using ngx.shared.DICT with atomic operations to prevent race conditions
--
-- Initial analysis identified a classic TOCTOU race condition when using separate
-- get/set calls: two concurrent requests could both read the same counter value,
-- both pass the limit check, and both set counter+1, effectively counting two
-- requests as one. This allows bypassing the rate limit under high concurrency.
--
-- Fix: Use ngx.shared.DICT:incr() which is an atomic operation implemented in
-- shared memory with spinlocks, eliminating the race condition entirely.

function _M.new(dict_name, limit, window_seconds)
    local dict = ngx.shared[dict_name]
    if not dict then
        return nil, "shared dictionary '" .. tostring(dict_name) .. "' not found"
    end

    local self = {
        dict = dict,
        limit = limit or 100,
        window = window_seconds or 60,
    }

    return setmetatable(self, { __index = _M })
end

function _M.check(self, key)
    local dict = self.dict
    local limit = self.limit
    local window = self.window

    -- Use incr with init value to atomically increment and initialize in one call.
    -- This avoids the race condition of separate get() -> check -> set() sequences.
    -- ngx.shared.DICT:incr() is implemented with a spinlock in shared memory,
    -- making it safe for concurrent access across all worker processes.
    --
    -- The 4th argument (init) was added in OpenResty 1.11.2.7+ and causes the
    -- key to be created with the init value if it doesn't exist, then incremented
    -- by the first argument — all atomically.
    local new_count, err = dict:incr(key, 1, 0, window)

    if not new_count then
        -- On error, fail open or closed depending on your policy.
        -- Failing closed is safer to prevent abuse.
        ngx.log(ngx.ERR, "rate limiter incr failed for key '", key, "': ", err)
        return nil, "rate limiter error: " .. tostring(err)
    end

    if new_count > limit then
        -- Calculate remaining TTL so caller can set Retry-After header
        local remaining_ttl = dict:ttl(key)
        return nil, "rate limit exceeded", {
            limit = limit,
            remaining = 0,
            reset_after = remaining_ttl or window,
            current = new_count,
        }
    end

    return true, nil, {
        limit = limit,
        remaining = limit - new_count,
        current = new_count,
    }
end

-- Convenience function to use directly in access_by_lua
function _M.limit_req(self, key)
    local ok, err, info = self:check(key)

    if not ok then
        if err == "rate limit exceeded" then
            ngx.header["X-RateLimit-Limit"] = tostring(info.limit)
            ngx.header["X-RateLimit-Remaining"] = "0"
            ngx.header["Retry-After"] = tostring(math.ceil(info.reset_after or self.window))
            ngx.status = 429
            ngx.say('{"error":"Too Many Requests","retry_after":' .. math.ceil(info.reset_after or self.window) .. '}')
            return ngx.exit(429)
        else
            -- Internal error — fail closed
            ngx.log(ngx.ERR, "rate limiter internal error: ", err)
            ngx.status = 500
            ngx.say('{"error":"Internal Server Error"}')
            return ngx.exit(500)
        end
    end

    -- Set response headers for successful requests
    ngx.header["X-RateLimit-Limit"] = tostring(info.limit)
    ngx.header["X-RateLimit-Remaining"] = tostring(info.remaining)

    return true
end

return _M

